63: func (r *REST) Create(ctx context.Context, obj runtime.Object, createValidation rest.ValidateObjectFunc, options *metav1.CreateOptions) (runtime.Object, error) {
64: 	subjectAccessReview, ok := obj.(*authorizationapi.SubjectAccessReview)
65: 	if !ok {
66: 		return nil, apierrors.NewBadRequest(fmt.Sprintf("not a SubjectAccessReview: %#v", obj))
67: 	}
68: 	// clear fields if the featuregate is disabled
69: 	if !utilfeature.DefaultFeatureGate.Enabled(genericfeatures.AuthorizeWithSelectors) {
70: 		if subjectAccessReview.Spec.ResourceAttributes != nil {
71: 			subjectAccessReview.Spec.ResourceAttributes.FieldSelector = nil
72: 			subjectAccessReview.Spec.ResourceAttributes.LabelSelector = nil
73: 		}
74: 	}
75: 	if errs := authorizationvalidation.ValidateSubjectAccessReview(subjectAccessReview); len(errs) > 0 {
76: 		return nil, apierrors.NewInvalid(authorizationapi.Kind(subjectAccessReview.Kind), "", errs)
77: 	}
78: 
79: 	if createValidation != nil {
80: 		if err := createValidation(ctx, obj.DeepCopyObject()); err != nil {
81: 			return nil, err
82: 		}
83: 	}
84: 
85: 	authorizationAttributes := authorizationutil.AuthorizationAttributesFrom(subjectAccessReview.Spec)
86: 	decision, reason, evaluationErr := r.authorizer.Authorize(ctx, authorizationAttributes)
87: 
88: 	subjectAccessReview.Status = authorizationapi.SubjectAccessReviewStatus{
89: 		Allowed: (decision == authorizer.DecisionAllow),
90: 		Denied:  (decision == authorizer.DecisionDeny),
91: 		Reason:  reason,
92: 	}
93: 	subjectAccessReview.Status.EvaluationError = authorizationutil.BuildEvaluationError(evaluationErr, authorizationAttributes)
94: 
95: 	return subjectAccessReview, nil
96: }
